import React, { useState, useEffect } from 'react';
import { Container, Form, Button, ListGroup, Badge } from 'react-bootstrap';
import api from '../services/api';
import { toast } from 'react-toastify';

export default function Forum() {
  const [title, setTitle] = useState('');
  const [body, setBody] = useState('');
  const [threads, setThreads] = useState([]);

  const fetchThreads = async () => {
    try {
      const res = await api.get('/forum/threads');
      setThreads(res.data);
    } catch (err) {
      console.error(err);
      toast.error('Failed to load threads');
    }
  };

  useEffect(() => { fetchThreads(); }, []);

  const create = async () => {
    try {
      const user = JSON.parse(localStorage.getItem('user'));
      if (!user) return toast.error('Please login');
      const res = await api.post('/forum/threads', { user_id: user.id, title, body });
      toast.info('Posted: ' + res.data.status);
      setTitle(''); setBody('');
      if (res.data.status === 'approved') fetchThreads();
    } catch (err) {
      toast.error(err.response?.data?.error || 'Failed to post');
    }
  };

  return (
    <Container className="mt-4">
      <h2>Community Forum</h2>
      <Form.Group className="mb-2"><Form.Control placeholder="Title" value={title} onChange={e=>setTitle(e.target.value)}/></Form.Group>
      <Form.Group className="mb-2"><Form.Control as="textarea" rows={4} placeholder="Share your thoughts..." value={body} onChange={e=>setBody(e.target.value)}/></Form.Group>
      <Button onClick={create} className="mb-3">Create Thread</Button>

      <h4>Approved Threads</h4>
      <ListGroup>
        {threads.map(t => (
          <ListGroup.Item key={t.id}>
            <div className="d-flex justify-content-between">
              <div><strong>{t.title}</strong><div className="small">{t.body}</div></div>
              <Badge bg="success">{t.status}</Badge>
            </div>
          </ListGroup.Item>
        ))}
      </ListGroup>
    </Container>
  );
}
